// Build week ranges: this week (last 7 days) vs previous week (7-14 days ago)
const now = new Date();
const d = n => new Date(now.getTime() - n * 86400000).toISOString().slice(0, 10);
return [{
  json: {
    ...$json,
    this_start: d(7),
    this_end: d(1),
    prev_start: d(14),
    prev_end: d(8),
  }
}];

// Aggregate everything into a single KPI snapshot
const dates = $('Build Date Ranges').first().json;

// GA4 — parse this week vs prev
const ga4 = $('GA4: Traffic').first()?.json?.rows || [];
function sumByRange(rangeName) {
  const row = ga4.find(r => r.dimensionValues?.[0]?.value === rangeName);
  if (!row) return { sessions: 0, users: 0, conversions: 0, engagementRate: 0 };
  const m = row.metricValues || [];
  return {
    sessions: parseInt(m[0]?.value || 0),
    users: parseInt(m[1]?.value || 0),
    conversions: parseInt(m[2]?.value || 0),
    engagementRate: parseFloat(m[3]?.value || 0),
  };
}
const ga4_this = sumByRange('this_week');
const ga4_prev = sumByRange('prev_week');

// Meta Ads
const meta = $('Meta Ads: Week').first()?.json?.data?.[0] || {};
const purchases = (meta.actions || []).find(a => a.action_type === 'purchase')?.value || 0;
const meta_kpi = {
  spend: parseFloat(meta.spend) || 0,
  impressions: parseInt(meta.impressions) || 0,
  clicks: parseInt(meta.clicks) || 0,
  purchases: parseInt(purchases) || 0,
  ctr: parseFloat(meta.ctr) || 0,
  cpc: parseFloat(meta.cpc) || 0,
  roas: parseFloat((meta.purchase_roas || [])[0]?.value || 0),
};

// Resend — count only (MVP)
const resend = $('Resend: Recent').first()?.json?.data || [];

// Notion sources
const leads = $('Notion: New Leads').all().map(i => i.json);
const hotLeads = leads.filter(l => l.properties?.hot_signal?.checkbox);
const published = $('Notion: Published').all().map(i => i.json);
const inbox = $('Notion: Inbox').all().map(i => i.json);
const inboxReplied = inbox.filter(i => i.properties?.status?.select?.name === 'replied');
const competitor = $('Notion: Competitor').all().map(i => i.json);
const seo = $('Notion: SEO Opps').all().map(i => i.json);
const seoNew = seo.filter(s => s.properties?.status?.select?.name === 'new');
const seoDone = seo.filter(s => s.properties?.status?.select?.name === 'done');

const trend = (curr, prev) => {
  if (prev === 0) return curr > 0 ? '+∞' : '0';
  return ((curr - prev) / prev * 100).toFixed(0) + '%';
};

const snapshot = {
  week_label: `${dates.this_start} ~ ${dates.this_end}`,
  traffic: {
    sessions: ga4_this.sessions,
    users: ga4_this.users,
    conversions: ga4_this.conversions,
    sessions_trend: trend(ga4_this.sessions, ga4_prev.sessions),
    conversions_trend: trend(ga4_this.conversions, ga4_prev.conversions),
  },
  ads: meta_kpi,
  email: { sent_count: resend.length },
  leads: {
    total: leads.length,
    hot: hotLeads.length,
  },
  content: {
    published_count: published.length,
  },
  inbox: {
    total: inbox.length,
    replied: inboxReplied.length,
    response_rate: inbox.length > 0 ? (inboxReplied.length / inbox.length * 100).toFixed(0) + '%' : 'n/a',
  },
  competitor: {
    high_impact_count: competitor.length,
  },
  seo: {
    open_opportunities: seoNew.length,
    completed: seoDone.length,
  },
};

return [{ json: snapshot }];

const raw = $json.message?.content?.[0]?.text || $json.content || $json.text;
let parsed;
try {
  parsed = typeof raw === 'string' ? JSON.parse(raw.replace(/^```json\s*|\s*```$/g, '')) : raw;
} catch (e) {
  parsed = { insights: [], actions: [], headline_metric: '', warning: '' };
}
const snap = $('Build KPI Snapshot').item.json;
return [{ json: { ...snap, analysis: parsed } }];

// Build Slack mrkdwn message
const d = $json;
const a = d.analysis;

let text = `📊 *Weekly Marketing Report* — ${d.week_label}\n`;
if (a.headline_metric) text += `\n⭐ ${a.headline_metric}\n`;
if (a.warning) text += `\n🚨 *${a.warning}*\n`;

text += `\n*Traffic*\n` +
  `• Sessions: ${d.traffic.sessions.toLocaleString()} (${d.traffic.sessions_trend})\n` +
  `• Users: ${d.traffic.users.toLocaleString()}\n` +
  `• Conversions: ${d.traffic.conversions} (${d.traffic.conversions_trend})\n`;

if (d.ads.spend > 0) {
  text += `\n*Ads (Meta)*\n` +
    `• Spend: $${d.ads.spend.toFixed(0)} · CTR: ${(d.ads.ctr).toFixed(2)}% · ROAS: ${d.ads.roas.toFixed(1)}x\n` +
    `• Purchases: ${d.ads.purchases}\n`;
}

text += `\n*Funnel*\n` +
  `• New leads: ${d.leads.total} (hot: ${d.leads.hot})\n` +
  `• Inbox: ${d.inbox.total} received · response ${d.inbox.response_rate}\n`;

text += `\n*Content & SEO*\n` +
  `• Published this week: ${d.content.published_count}\n` +
  `• SEO opportunities open: ${d.seo.open_opportunities} · completed: ${d.seo.completed}\n`;

if (d.competitor.high_impact_count > 0) {
  text += `\n*Competitor*\n• High-impact changes: ${d.competitor.high_impact_count}\n`;
}

if (a.insights?.length) {
  text += `\n*🔍 Insights*\n`;
  a.insights.forEach((ins, i) => {
    text += `${i+1}. *${ins.title}* — ${ins.detail}\n`;
  });
}

if (a.actions?.length) {
  text += `\n*✅ This Week's Actions*\n`;
  a.actions.forEach((act, i) => {
    text += `${i+1}. *${act.title}*\n   _${act.why}_`;
    if (act.linked_automation && act.linked_automation !== 'none') {
      text += ` → \`${act.linked_automation}\``;
    }
    text += `\n`;
  });
}

return [{ json: { text, snapshot: d } }];
